/**
 * Initializes the calendar popup with AJAX month/year navigation.
 * Updates calendar grid dynamically without page reload.
 */
function initCalendarPopup() {
  const dialog = document.getElementById("calendar-dialog");
  const openButton = document.getElementById("calendar-open");
  const closeButton = document.getElementById("calendar-close");
  const calendarGrid = document.getElementById("calendar-grid");
  const monthSelect = document.getElementById("calendar-month-select");
  const yearSelect = document.getElementById("calendar-year-select");
  const prevButton = document.getElementById("calendar-prev");
  const nextButton = document.getElementById("calendar-next");
  const todayButton = document.getElementById("calendar-today");
  const gridUrl = dialog?.dataset?.gridUrl || "/api/calendar-grid/";
  const todayMonth = parseInt(dialog?.dataset?.todayMonth || "1", 10);
  const todayYear = parseInt(dialog?.dataset?.todayYear || "2026", 10);

  if (!dialog || !openButton || !closeButton || !calendarGrid || !monthSelect || !yearSelect) {
    return;
  }

  // Track current month/year from selects
  let currentMonth = parseInt(monthSelect.value, 10);
  let currentYear = parseInt(yearSelect.value, 10);

  /**
   * Updates the calendar grid by fetching new HTML from server.
   * Inserts the rendered grid without reloading the page.
   */
  async function updateCalendarGrid(month, year) {
    try {
      const params = new URLSearchParams({
        month: String(month),
        year: String(year),
      });
      const response = await fetch(`${gridUrl}?${params.toString()}`, {
        headers: {
          "X-Requested-With": "XMLHttpRequest",
        },
      });
      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }
      const html = await response.text();
      // Replace grid content with new HTML
      calendarGrid.innerHTML = html;
    } catch (error) {
      console.error("Failed to update calendar grid:", error);
    }
  }

  /**
   * Ensures the given year exists as an option in the year select.
   */
  function ensureYearOption(year) {
    const optionExists = Array.from(yearSelect.options).some((option) => parseInt(option.value, 10) === year);
    if (!optionExists) {
      const newOption = document.createElement("option");
      newOption.value = String(year);
      newOption.textContent = String(year);
      yearSelect.appendChild(newOption);
    }
  }

  /**
   * Sets the active month/year in selectors and refreshes the grid.
   */
  async function setMonthYear(month, year) {
    const safeMonth = Math.max(1, Math.min(12, month));
    const safeYear = Math.max(1900, Math.min(2100, year));

    ensureYearOption(safeYear);
    currentMonth = safeMonth;
    currentYear = safeYear;
    monthSelect.value = String(safeMonth);
    yearSelect.value = String(safeYear);
    await updateCalendarGrid(currentMonth, currentYear);
  }

  /**
   * Opens the calendar dialog and updates accessibility state.
   */
  function openDialog() {
    if (typeof dialog.showModal === "function") {
      dialog.showModal();
    } else {
      dialog.setAttribute("open", "");
    }
    openButton.setAttribute("aria-expanded", "true");
  }

  /**
   * Closes the calendar dialog and updates accessibility state.
   */
  function closeDialog() {
    if (dialog.hasAttribute("open")) {
      dialog.close?.();
      dialog.removeAttribute("open");
    }
    openButton.setAttribute("aria-expanded", "false");
  }

  // Event listeners
  openButton.addEventListener("click", () => {
    openDialog();
  });

  closeButton.addEventListener("click", () => {
    closeDialog();
  });

  monthSelect.addEventListener("change", async (e) => {
    await setMonthYear(parseInt(e.target.value, 10), currentYear);
  });

  yearSelect.addEventListener("change", async (e) => {
    await setMonthYear(currentMonth, parseInt(e.target.value, 10));
  });

  prevButton?.addEventListener("click", async () => {
    let targetMonth = currentMonth - 1;
    let targetYear = currentYear;
    if (targetMonth < 1) {
      targetMonth = 12;
      targetYear -= 1;
    }
    await setMonthYear(targetMonth, targetYear);
  });

  nextButton?.addEventListener("click", async () => {
    let targetMonth = currentMonth + 1;
    let targetYear = currentYear;
    if (targetMonth > 12) {
      targetMonth = 1;
      targetYear += 1;
    }
    await setMonthYear(targetMonth, targetYear);
  });

  todayButton?.addEventListener("click", async () => {
    await setMonthYear(todayMonth, todayYear);
  });

  // Close dialog when clicking outside
  dialog.addEventListener("click", (event) => {
    const dialogBox = dialog.getBoundingClientRect();
    const clickedOutside =
      event.clientX < dialogBox.left ||
      event.clientX > dialogBox.right ||
      event.clientY < dialogBox.top ||
      event.clientY > dialogBox.bottom;

    if (clickedOutside) {
      closeDialog();
    }
  });

  dialog.addEventListener("cancel", (event) => {
    event.preventDefault();
    closeDialog();
  });

  dialog.addEventListener("close", () => {
    openButton.setAttribute("aria-expanded", "false");
  });

  openButton.setAttribute("aria-expanded", "false");
}

  /**
   * Close dialog before navigating to a post link.
   */
  function handleCalendarLinkClicks() {
    function closeAndFollow(e) {
      // Only handle left-click or keyboard activation
      if (
        e.type === "click" && (e.button !== 0 || e.metaKey || e.ctrlKey || e.altKey || e.shiftKey)
      ) {
        return;
      }
      const link = e.currentTarget;
      if (dialog && typeof dialog.close === "function") {
        dialog.close();
      }
      // Let navigation proceed after closing
    }
    // Delegate for all .calendar-day-link inside the dialog
    dialog.addEventListener("click", function (event) {
      const target = event.target.closest(".calendar-day-link");
      if (target && dialog.contains(target)) {
        closeAndFollow(event);
      }
    });
    // Keyboard accessibility: Enter/Space on link
    dialog.addEventListener("keydown", function (event) {
      if ((event.key === "Enter" || event.key === " ") && document.activeElement?.classList.contains("calendar-day-link")) {
        closeAndFollow(event);
      }
    });
  }

// Initialize when DOM is ready
if (document.readyState === "loading") {
  document.addEventListener("DOMContentLoaded", initCalendarPopup);
} else {
  initCalendarPopup();
}

// Generated by GitHub Copilot
if (typeof window !== "undefined") {
  window.addEventListener("DOMContentLoaded", function () {
    const dialog = document.getElementById("calendar-dialog");
    if (dialog) {
      // Attach link close handler after DOM is ready
      if (typeof handleCalendarLinkClicks === "function") {
        handleCalendarLinkClicks();
      }
    }
  });
}
